mapper.select:
SELECT ,
       u.name AS user_name,
       p.name AS project_name,
       m.name AS module_name
FROM tb_work_hour wh
LEFT JOIN tb_user u ON wh.user_id = u.id
LEFT JOIN tb_project p ON wh.project_id = p.id
LEFT JOIN tb_task_module m ON wh.module_id = m.id
WHERE wh.is_deleted = 0

    AND wh.user_id = #{userId}


    AND wh.project_id = #{projectId}


    AND wh.work_date >= #{startDate}


    AND wh.work_date <= #{endDate}


    AND wh.status = #{status}

ORDER BY wh.work_date DESC, wh.create_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM tb_work_hour wh
WHERE wh.is_deleted = 0

    AND wh.user_id = #{userId}


    AND wh.project_id = #{projectId}


    AND wh.work_date >= #{startDate}


    AND wh.work_date <= #{endDate}


    AND wh.status = #{status}

