SELECT COUNT(DISTINCT wh.user_id) AS submitCount, COALESCE(SUM(wh.hours), 0) AS totalHours FROM tb_work_hour wh WHERE wh.is_deleted = 0 AND wh.work_date = CURDATE()
AND wh.project_id IN (SELECT id FROM tb_project WHERE manager_id = #{userId})
AND wh.user_id = #{userId}

